run("gcc -shared mods_src/views.c -o mods/views.dll libcont.a libvmstack.a libvmvar.a libvmstate.a libvmstore.a libvm.a libdxgfx.a -lws2_32 -ladvapi32")
run("gcc -shared mods_src/views_render.c -o mods/views_render.dll libcont.a libvmstate.a libvmvar.a libvmstore.a libvm.a libdxgfx.a -lws2_32 -ladvapi32")

# hash rename views + views_render
tokens_path = root / "atomic_mod_tokens.txt"
mapping = {}
for line in tokens_path.read_text(encoding="ascii").splitlines():
    if "=" in line:
        n,v=line.split("=",1); mapping[n]=v

for name in ["views", "views_render"]:
    src = root / "mods" / f"{name}.dll"
    data = src.read_bytes()
    h = hashlib.sha256(data).hexdigest()
    dst = root / "mods" / f"{h}.dll"
    if src.resolve() != dst.resolve():
        if dst.exists():
            src.unlink()
        else:
            src.rename(dst)
    mapping[name] = h
    print(f"{name} -> {h}")

tokens_path.write_text("\n".join(f"{k}={mapping[k]}" for k in sorted(mapping))+"\n", encoding="ascii")
print("tokens updated")"}

